const items = $input.all();
const competitorUrls = [];

for (const item of items) {
  const text = typeof item.json === 'string' ? item.json : JSON.stringify(item.json);
  const urlPattern = /https?:\/\/[^\s"'<>)]+\/[^\s"'<>)]+/gi;
  const matches = text.match(urlPattern) || [];

  for (const url of matches) {
    // Extract keywords from URL path
    const path = new URL(url).pathname.toLowerCase();
    const keywords = path
      .replace(/\.(xml|html|php|aspx?)$/, '')
      .split(/[\/-]/)
      .filter(s => s.length > 2 && !['www', 'tools', 'calculator', 'calculators', 'free', 'online', 'the'].includes(s));

    if (keywords.length > 0) {
      competitorUrls.push({ url, keywords: [...new Set(keywords)] });
    }
  }
}

return competitorUrls;

const text = typeof $input.first().json === 'string' ? $input.first().json : JSON.stringify($input.first().json);
const urlPattern = /https?:\/\/sectorcalc\.com[^\s"'<>)]+/gi;
const matches = text.match(urlPattern) || [];
return matches.map(url => {
  const path = new URL(url).pathname.toLowerCase();
  const keywords = path.split(/[\/-]/).filter(s => s.length > 2 && !['www', 'tools', 'free', 'pro', 'premium']).filter(Boolean);
  return { url, keywords: [...new Set(keywords)] };
});

const competitorItems = $input.all().filter((_, i) => i < $input.all().length / 2 + 1);
const ourItems = $input.all().filter((_, i) => i >= $input.all().length / 2 + 1);

// Flatten competitor keywords into a set
const competitorKeywords = new Set();
for (const item of competitorItems) {
  for (const kw of (item.json.keywords || [])) {
    competitorKeywords.add(kw.toLowerCase());
  }
}

// Flatten our keywords into a set
const ourKeywords = new Set();
for (const item of ourItems) {
  for (const kw of (item.json.keywords || [])) {
    ourKeywords.add(kw.toLowerCase());
  }
}

// Find gaps = competitor has, we don't
const gaps = [...competitorKeywords].filter(kw => !ourKeywords.has(kw) && kw.length > 2 && !['com', 'www', 'net', 'org', 'php', 'html', 'asp'].includes(kw));

// Remove common noise words
const noiseWords = new Set(['page', 'category', 'tag', 'author', 'feed', 'index', 'home', 'blog', 'post', 'search', 'about', 'contact', 'terms', 'privacy', 'sitemap']);
const cleanGaps = gaps.filter(kw => !noiseWords.has(kw));

return cleanGaps.map(keyword => ({
  keyword,
  competitorUrls: competitorItems.filter(item => (item.json.keywords || []).some(k => k.toLowerCase() === keyword)).map(item => item.json.url),
  detectedAt: new Date().toISOString()
}));
